# Shapes module: Shape class hierarchy using types module
from types import ShapeCategory, Point, IRenderable, IMeasurable

@abstract
class Shape(IRenderable):
    category: ShapeCategory
    position: Point

    def __init__(self, category: ShapeCategory, pos: Point):
        self.category = category
        self.position = pos

    @virtual
    def describe(self) -> str:
        return f"Shape at ({self.position.x}, {self.position.y})"

class Rectangle(Shape, IMeasurable):
    width: float
    height: float

    def __init__(self, pos: Point, width: float, height: float):
        super().__init__(ShapeCategory.PLANE, pos)
        self.width = width
        self.height = height

    @override
    def render(self) -> str:
        return f"Rectangle({self.width} x {self.height})"

    @override
    def describe(self) -> str:
        return f"Rectangle at ({self.position.x}, {self.position.y})"

    def get_area(self) -> float:
        return self.width * self.height

class Circle(Shape, IMeasurable):
    radius: float

    def __init__(self, pos: Point, radius: float):
        super().__init__(ShapeCategory.PLANE, pos)
        self.radius = radius

    @override
    def render(self) -> str:
        return f"Circle(r={self.radius})"

    @override
    def describe(self) -> str:
        return f"Circle at ({self.position.x}, {self.position.y})"

    def get_area(self) -> float:
        return 3.14159 * self.radius * self.radius

