# Utils module: Factory and helper functions
from types import Point, ShapeCategory
from shapes import Shape, Rectangle, Circle

class ShapeFactory:
    @static
    _count: int = 0

    @static
    def create_rectangle(x: float, y: float, w: float, h: float) -> Rectangle:
        ShapeFactory._count += 1
        return Rectangle(Point(x, y), w, h)

    @static
    def create_circle(x: float, y: float, r: float) -> Circle:
        ShapeFactory._count += 1
        return Circle(Point(x, y), r)

    @static
    def get_count() -> int:
        return ShapeFactory._count

def calculate_total_area(areas: list[float]) -> float:
    total: float = 0.0
    for area in areas:
        total += area
    return total

def format_point(p: Point) -> str:
    return f"({p.x}, {p.y})"
